// Validate secret and extract routing action
const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');
const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

// Extract routing action FIRST (Pitfall 2: field name collision)
const route_action = body.action;
if (!route_action) throw new Error('Missing required field: action');
const validActions = ['create_scene', 'list_scenes', 'update_scene', 'invalidate_scene'];
if (!validActions.includes(route_action)) throw new Error(`Invalid action: ${route_action}`);

const content_id = body.content_id;
if (!content_id) throw new Error('Missing required field: content_id');

// Pass all body fields forward, but mark the routing action separately
return [{ json: { route_action, content_id, ...body, action: undefined, secret: undefined } }];

// Execute scene CRUD action against NocoDB scenes table
const input = $input.first().json;
const { route_action, content_id } = input;

const baseUrl = $env.NOCODB_BASE_URL;
const token = $env.NOCODB_API_TOKEN;
let baseId = $env.NOCODB_CF_BASE_ID || '';
let scenesId = $env.NOCODB_SCENES_TABLE_ID || '';

// Resolve table IDs via meta API if not set
if (!baseId || !scenesId) {
  const basesResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v2/meta/bases/`,
    headers: { 'xc-token': token }
  });
  const base = (basesResp.list || []).find(b => b.title === 'content-factory');
  if (!base) throw new Error('NocoDB base content-factory not found');
  baseId = base.id;

  const tablesResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v2/meta/bases/${baseId}/tables`,
    headers: { 'xc-token': token }
  });
  const scenesTable = (tablesResp.list || []).find(t => t.title === 'scenes');
  if (!scenesTable) throw new Error('NocoDB table scenes not found');
  scenesId = scenesTable.id;
}

const apiBase = `${baseUrl}/api/v2/meta/bases/${baseId}/tables/${scenesId}/records`;
const headers = { 'xc-token': token, 'Content-Type': 'application/json' };

if (route_action === 'create_scene') {
  const result = await $http.request({
    method: 'POST',
    url: apiBase,
    headers,
    body: {
      content_id: String(content_id),
      scene_number: input.scene_number || 1,
      description: input.description || '',
      duration_sec: input.duration || 0,
      dialogue: input.dialogue || '',
      screen_text: input.screen_text || '',
      transition: input.transition || 'cut',
      status: input.status || 'draft',
      provider: input.provider || '',
      scene_action: input.scene_action || ''
    }
  });
  return [{ json: { status: 'ok', scene_id: String(result.Id) } }];
}

if (route_action === 'list_scenes') {
  const resp = await $http.request({
    method: 'GET',
    url: apiBase,
    headers: { 'xc-token': token },
    qs: { where: `(content_id,eq,${content_id})`, sort: 'scene_number', limit: 100 }
  });
  return [{ json: { scenes: resp.list || [] } }];
}

if (route_action === 'update_scene') {
  const scene_number = input.scene_number;
  if (!scene_number) throw new Error('Missing required field: scene_number for update_scene');

  // Find scene by content_id + scene_number
  const findResp = await $http.request({
    method: 'GET',
    url: apiBase,
    headers: { 'xc-token': token },
    qs: { where: `(content_id,eq,${content_id})~and(scene_number,eq,${scene_number})`, limit: 1 }
  });
  const sceneRow = (findResp.list || [])[0];
  if (!sceneRow) throw new Error(`Scene not found: content_id=${content_id}, scene_number=${scene_number}`);

  const patchFields = {};
  if (input.asset_url !== undefined) patchFields.asset_url = input.asset_url;
  if (input.provider !== undefined) patchFields.provider = input.provider;
  if (input.status !== undefined) patchFields.status = input.status;
  if (input.description !== undefined) patchFields.description = input.description;
  if (input.duration !== undefined) patchFields.duration_sec = input.duration;

  await $http.request({
    method: 'PATCH',
    url: apiBase,
    headers,
    body: { Id: sceneRow.Id, ...patchFields }
  });
  return [{ json: { status: 'ok', scene_id: String(sceneRow.Id) } }];
}

if (route_action === 'invalidate_scene') {
  const scene_id = input.scene_id;
  if (!scene_id) throw new Error('Missing required field: scene_id for invalidate_scene');

  await $http.request({
    method: 'PATCH',
    url: apiBase,
    headers,
    body: { Id: parseInt(scene_id), status: 'invalidated', asset_url: '' }
  });
  return [{ json: { status: 'ok', scene_id: String(scene_id) } }];
}

throw new Error(`Unhandled action: ${route_action}`);
